import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const ForgotPassword: React.FC = () => {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setStatus(null);

    if (!email.trim()) {
      setError('Please enter your email.');
      return;
    }

    try {
      const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8000';
      const res = await fetch(`${apiUrl}/api/auth/forgot-password`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });
      if (!res.ok) {
        const text = await res.text();
        throw new Error(text || 'Request failed');
      }

      setStatus('If that email exists, a password reset link was sent.');
      // optionally navigate after a delay
      setTimeout(() => navigate('/login'), 2500);
    } catch (err) {
      setError((err as Error).message || 'Failed to send reset link. Please try again later.');
    }
  };

  return (
    <div className="max-w-md mx-auto mt-12 p-6 bg-[#0a0a0a] rounded-lg shadow-xl border border-[#C5A059]/30 glass text-white">
      <h2 className="text-2xl font-semibold mb-4 text-[#C5A059]">Reset Password</h2>
      <p className="text-sm mb-4 text-slate-300">Enter your email to receive a password reset link.</p>
      <form onSubmit={handleSubmit}>
        <label className="block mb-4">
          <span className="text-sm font-medium text-slate-300">Email</span>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="mt-1 block w-full rounded bg-[#020202] border border-slate-700/50 text-white shadow-sm focus:ring-[#00FF41]/50 focus:border-[#00FF41]/50"
            placeholder="you@example.com"
            required
          />
        </label>

        {error && <div className="text-[#FF3E3E] mb-3 text-sm">{error}</div>}
        {status && <div className="text-[#00FF41] mb-3 text-sm">{status}</div>}

        <button
          type="submit"
          className="w-full bg-[#00FF41] text-[#020202] py-2 rounded font-bold hover:bg-[#00FF41]/80 disabled:opacity-50 transition-colors"
        >
          Send reset link
        </button>
      </form>
    </div>
  );
};

export default ForgotPassword;
